ail »"},{"type":"text","text":" ouvre un "},{"type":"text","marks":[{"type":"bold"}],"text":"tableau"},{"type":"text","text":" — en lignes les habitantes (classées "},{"type":"text","marks":[{"type":"bold"}],"text":"résidence → étage → chambre → nom"},{"type":"text","text":", invitées en fin de résidence), en colonnes les jours, chaque case indiquant "},{"type":"text","marks":[{"type":"bold"}],"text":"P"},{"type":"text","text":" (au foyer) ou "},{"type":"text","marks":[{"type":"bold"}],"text":"A"},{"type":"text","text":" (sortie). "},{"type":"text","marks":[{"type":"italic"}],"text":"Cette structure de tableau est réutilisée partout (présences, repas) pour ne pas se perdre."}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Marquer une absence ou une présence"},{"type":"text","text":" : bouton "},{"type":"text","marks":[{"type":"bold"}],"text":"« Ajouter une absence »"},{"type":"text","text":"."}]},{"type":"orderedList","attrs":{"start":1,"type":null},"content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Choisis la "},{"type":"text","marks":[{"type":"bold"}],"text":"résidence"},{"type":"text","text":", puis la "},{"type":"text","marks":[{"type":"bold"}],"text":"personne"},{"type":"text","text":" (résidente ou invitée à compte)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Choisis "},{"type":"text","marks":[{"type":"bold"}],"text":"« Absente »"},{"type":"text","text":" (crée un séjour) ou "},{"type":"text","marks":[{"type":"bold"}],"text":"« Présente »"},{"type":"text","text":" (retire les absences déjà déclarées sur la période — pour corriger ou faire revenir quelqu''un)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Renseigne la "},{"type":"text","marks":[{"type":"bold"}],"text":"période"},{"type":"text","text":" et, pour une absence, un "},{"type":"text","marks":[{"type":"bold"}],"text":"contact"},{"type