es × jours/service ; chaque case = l''option choisie, ou 🌙 "},{"type":"text","marks":[{"type":"bold"}],"text":"lune orange"},{"type":"text","text":" = absente, ou "},{"type":"text","marks":[{"type":"bold"}],"text":"Non"},{"type":"text","text":" en rouge = ne mange pas). Un invité y apparaît en "},{"type":"text","marks":[{"type":"bold"}],"text":"petit badge « +👤 Prénom »"},{"type":"text","text":" dans la case de la personne qui l''a invité (jamais de ligne à part)."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Onglet « Comptabilité »"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Récapitulatif de la période"},{"type":"text","text":" : total déjeuners / dîners "},{"type":"text","marks":[{"type":"bold"}],"text":"par résidence"},{"type":"text","text":", et un "},{"type":"text","marks":[{"type":"bold"}],"text":"grand total"},{"type":"text","text":"."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Agrégat par personne"},{"type":"text","text":" : pour chaque personne, nombre de déjeuners et de dîners (les « Non » et les jours d''absence ne comptent pas), "},{"type":"text","marks":[{"type":"bold"}],"text":"invités inclus"},{"type":"text","text":" pour la personne qui les a invités. "},{"type":"text","marks":[{"type":"bold"}],"text":"Toutes les résidentes"},{"type":"text","text":" apparaissent, même celles inscrites à rien (0). La liste est triée "},{"type":"text","marks":[{"type":"bold"}],"text":"par nom puis prénom"},{"type":"text","text":" pour faciliter la facturation."}]}]}]},{"type":"blockquote","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Déduction des absences"},{"type":"text","text":" : un séjour d''absence retire automatiquement les repas des "},{"type":"text","marks":[{"type":"bold"}],"text":"jours intérieurs"},{"type":"text","text":" ; le "},{"type":"text","marks":[{"type":"bold"}],"text":"premier"},{"type":"text","text":" et le "},{"type":"text","marks":[{"type":"bold"}],"text":"dernier"},{"type":"text","text":" jour restent au libre choix de la résidente (elle part après le dîner, revient avant le déjeuner)."}]}]},{"type":"horizontalRule"},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"9. Événements & calendrier"}]},{"type":"paragraph","content":[{"type":"text","text":"Depuis le calendrier, une administratrice peut "},{"type":"text","marks":[{"type":"bold"}],"text":"créer, modifier et supprimer"},{"type":"text","text":" des événements :"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"titre, dates (une ou plusieurs), horaires, lieu (résidence·s), couleur ;"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"visibilité par noms"},{"type":"text","text":" : après avoir ciblé une ou des "},{"type":"text","marks":[{"type":"bold"}],"text":"résidences / étages"},{"type":"text","text":", la liste des "},{"type":"text","marks":[{"type":"bold"}],"text":"résidentes concernées"},{"type":"text","text":" s''affiche, pré-cochée ; on peut "},{"type":"text","marks":[{"type":"bold"}],"text":"décocher"},{"type":"text","text":" individuellement pour exclure quelqu''un. Le ciblage est "},{"type":"text","marks":[{"type":"bold"}],"text":"dynamique"},{"type":"text","text":" (les futures arrivantes correspondant au filtre sont incluses automatiquement). Une case "},{"type":"text","marks":[{"type":"bold"}],"text":"réservé admin"},{"type":"text","text":" limite la visibilité à l''intendance ;"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"rappel"},{"type":"text","text":" (nombre de jours avant) ;"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"demande de "},{"type":"text","marks":[{"type":"bold"}],"text":"confirmation de participation"},{"type":"text","text":" (avec vue des confirmations reçues)."}]}]}]},{"type":"horizontalRule"},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"10. Espace Administratif (infos pratiques)"}]},{"type":"paragraph","content":[{"type":"text","text":"L''onglet 📖 "},{"type":"text","marks":[{"type":"bold"}],"text":"Administratif"},{"type":"text","text":" (barre du bas) est "},{"type":"text","marks":[{"type":"bold"}],"text":"consultable par toutes"},{"type":"text","text":" mais "},{"type":"text","marks":[{"type":"bold"}],"text":"modifiable par les admins"},{"type":"text","text":" (bouton "},{"type":"text","marks":[{"type":"bold"}],"text":"« Modifier »"},{"type":"text","text":"). On y gère des "},{"type":"text","marks":[{"type":"bold"}],"text":"rubriques libres"},{"type":"text","text":" :"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Ajouter / renommer / réordonner / supprimer"},{"type":"text","text":" des rubriques ;"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"rubrique "},{"type":"text","marks":[{"type":"bold"}],"text":"texte"},{"type":"text","text":" (éditeur de mise en forme : gras, listes, titres, liens) ou rubrique "},{"type":"text","marks":[{"type":"bold"}],"text":"Contacts"},{"type":"text","text":" structurés (nom, rôle, téléphone, email cliquables) ;"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"une rubrique peut être "},{"type":"text","marks":[{"type":"bold"}],"text":"réservée aux administratrices"},{"type":"text","text":" (🔒) : elle n''est alors "},{"type":"text","marks":[{"type":"bold"}],"text":"pas visible"},{"type":"text","text":" par les résidentes (ex. le présent mode d''emploi)."}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Utilise-le pour le "},{"type":"text","marks":[{"type":"bold"}],"text":"règlement"},{"type":"text","text":", les "},{"type":"text","marks":[{"type":"bold"}],"text":"horaires"},{"type":"text","text":", les "},{"type":"text","marks":[{"type":"bold"}],"text":"contacts"},{"type":"text","text":", les "},{"type":"text","marks":[{"type":"bold"}],"text":"modes d''emploi"},{"type":"text","text":" et toute information générale du foyer."}]},{"type":"horizontalRule"},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"italic"}],"text":"Ce document accompagne le déploiement de l''application dans de nouveaux foyers. Le tenir à jour à chaque évolution fonctionnelle."}]}]}'
